**Missing Coverage:**
- Model selection logic based on prompt length, keywords, and categories
- Category-based routing (security → Opus, code-review → Sonnet)
- Profile hint overrides
- Keyword matching logic

**Test Skeleton:**

```typescript
// test/integration/model-router.test.ts
import { describe, it, expect } from "vitest";
import { selectModel, TIERS } from "@zana/core/src/model-router.ts";

describe("model-router", () => {
  describe("selectModel", () => {
    it("respects explicit model override", () => {
      const result = selectModel("any prompt", { model: "claude-haiku-4-5" });
      expect(result).toBe("claude-haiku-4-5");
    });

    it("routes long prompts to Opus", () => {
      const longPrompt = "a".repeat(2001);
      expect(selectModel(longPrompt)).toBe(TIERS.OPUS);
    });

    it("routes short list queries to Haiku", () => {
      expect(selectModel("list all files")).toBe(TIERS.HAIKU);
      expect(selectModel("show status", {})).toBe(TIERS.HAIKU);
    });

    it("routes architecture keywords to Opus", () => {
      expect(selectModel("design the system architecture")).toBe(TIERS.OPUS);
      expect(selectModel("refactor across modules")).toBe(TIERS.OPUS);
    });

    it("routes security category to Opus", () => {
      expect(selectModel("review code", { category: "security" })).toBe(TIERS.OPUS);
    });

    it("routes code-review category to Sonnet", () => {
      expect(selectModel("check this code", { category: "code-review" })).toBe(TIERS.SONNET);
    });

    it("defaults to Sonnet for generic prompts", () => {
      expect(selectModel("implement feature")).toBe(TIERS.SONNET);
    });

    it("handles empty prompt", () => {
      expect(selectModel("")).toBe(TIERS.SONNET);
      expect(selectModel(null)).toBe(TIERS.SONNET);
    });
  });
});
