**Missing Coverage:**
- Goal state parsing from natural language
- A* pathfinding algorithm
- DAG layer construction for parallelization
- Precondition/effect state satisfaction
- Replanning after failures
- Cost calculation and estimation

**Critical Edge Cases:**
- No valid plan found (unreachable goal)
- Circular dependencies in actions
- Plan cancellation during execution
- Agent spawn failures mid-plan

**Test Skeleton:**

```typescript
// test/integration/goap-planner.test.ts
import { describe, it, expect, beforeEach } from "vitest";
import { createPlan, executePlan, cancelPlan, registerAction, replan } from "@zana/core/src/goap-planner.ts";

describe("goap-planner", () => {
  describe("createPlan", () => {
    it("creates a plan for simple goal", () => {
      const result = createPlan("implement user authentication");
      expect(result.planId).toBeDefined();
      expect(result.layers.length).toBeGreaterThan(0);
      expect(result.estimatedCost).toBeGreaterThan(0);
    });

    it("throws when no valid plan exists", () => {
      expect(() => createPlan("impossible goal", {
        goalState: { impossibleState: true },
        initialState: {}
      })).toThrow("No valid plan found");
    });

    it("parses goal keywords correctly", () => {
      const result = createPlan("design and implement feature with tests");
      // Should recognize: architect, implement, test keywords
      expect(result.layers.length).toBeGreaterThanOrEqual(3);
    });

    it("creates parallel layers when no dependencies", () => {
      registerAction({
        id: "parallel-task-1",
        effects: { task1Done: true },
        preconditions: {},
        cost: 1,
        profileId: "test"
      });
      registerAction({
        id: "parallel-task-2",
        effects: { task2Done: true },
        preconditions: {},
        cost: 1,
        profileId: "test"
      });

      const result = createPlan("test", {
        goalState: { task1Done: true, task2Done: true },
        initialState: {}
      });
      // First layer should contain both tasks (parallel)
      expect(result.layers[0].length).toBe(2);
    });
  });

  describe("executePlan", () => {
    it("rejects execution of non-existent plan", async () => {
      await expect(executePlan("fake-id")).rejects.toThrow("Plan not found");
    });

    it("rejects double execution", async () => {
      const { planId } = createPlan("test goal");
      const promise1 = executePlan(planId);
      await expect(executePlan(planId)).rejects.toThrow("already running");
      await cancelPlan(planId); // cleanup
    });
  });

  describe("replan", () => {
    it("returns success when goal already achieved", () => {
      const { planId } = createPlan("test", {
        goalState: { done: true },
        initialState: { done: true }
      });
      const result = replan(planId);
      expect(result.success).toBe(true);
      expect(result.newLayers?.length).toBe(0);
    });

    it("finds alternative path after failure", () => {
      // Setup plan with optional paths
      const { planId } = createPlan("implement feature");
      const result = replan(planId);
      expect(result).toBeDefined();
    });
  });
});
