**Missing Coverage:**
- Condition evaluation (JS eval security!)
- Template interpolation with nested properties
- Step execution (spawn, gate, notify, wait)
- Concurrent run limits
- Step halting and error handling

**Security Critical:**
- `evaluateCondition` uses `new Function()` - needs injection testing
- `interpolatePrompt` - template injection testing

**Test Skeleton:**

```typescript
// test/integration/workflow-engine.test.ts
import { describe, it, expect } from "vitest";
import { executeWorkflow, evaluateCondition, MAX_STEPS, MAX_CONCURRENT_RUNS } from "@zana/core/src/workflow-engine.ts";

describe("workflow-engine", () => {
  describe("evaluateCondition", () => {
    it("evaluates simple conditions", () => {
      expect(evaluateCondition("true", {})).toBe(true);
      expect(evaluateCondition("false", {})).toBe(false);
    });

    it("accesses context variables", () => {
      expect(evaluateCondition("ticket.priority === 'high'", {
        ticket: { priority: "high" }
      })).toBe(true);
    });

    it("returns false on evaluation error", () => {
      expect(evaluateCondition("invalid..syntax", {})).toBe(false);
    });

    it("prevents malicious code execution", () => {
      // Should not allow process.exit, require, etc.
      expect(evaluateCondition("process.exit(1)", {})).toBe(false);
      expect(evaluateCondition("require('fs')", {})).toBe(false);
    });
  });

  describe("executeWorkflow", () => {
    it("rejects workflows with no steps", async () => {
      const result = await executeWorkflow({ id: "test", name: "Test", steps: [] });
      expect(result.error).toBe("no_steps");
    });

    it("rejects workflows exceeding MAX_STEPS", async () => {
      const steps = Array(MAX_STEPS + 1).fill({ action: "wait", durationMs: 1 });
      const result = await executeWorkflow({ id: "test", name: "Test", steps });
      expect(result.error).toBe("too_many_steps");
    });

    it("enforces MAX_CONCURRENT_RUNS", async () => {
      // Start MAX_CONCURRENT_RUNS workflows
      const promises = [];
      for (let i = 0; i < MAX_CONCURRENT_RUNS; i++) {
        promises.push(executeWorkflow({
          id: `test-${i}`,
          name: "Test",
          steps: [{ action: "wait", durationMs: 5000 }]
        }));
      }

      // Next one should fail
      const result = await executeWorkflow({
        id: "overflow",
        name: "Overflow",
        steps: [{ action: "wait", durationMs: 1 }]
      });
      expect(result.error).toBe("max_concurrent_runs");
    });

    it("halts on failed gate condition", async () => {
      const result = await executeWorkflow({
        id: "test",
        name: "Test",
        steps: [{ action: "gate", condition: "false" }]
      });
      expect(result.status).toBe("halted");
    });

    it("interpolates templates in prompts", async () => {
      // Test template interpolation
      const result = await executeWorkflow({
        id: "test",
        name: "Test",
        steps: [{
          action: "spawn",
          profile: "test-profile",
          prompt: "Process {{ticket.title}}"
        }]
      }, { ticket: { title: "Bug Fix" } });

      expect(result.steps[0].result?.prompt).toContain("Bug Fix");
    });
  });
});
