**Test Skeleton:**

```typescript
// test/integration/task-router.test.ts
import { describe, it, expect, beforeEach } from "vitest";
import { init, route, recordOutcome, getStats, reset } from "@zana/core/src/task-router.ts";

describe("task-router", () => {
  beforeEach(() => {
    reset();
    init();
  });

  describe("route", () => {
    it("returns empty array when no profiles match", () => {
      const result = route({ id: "test", title: "xyzabc nonexistent" });
      expect(Array.isArray(result)).toBe(true);
    });

    it("scores profiles by label history", () => {
      recordOutcome({
        ticketId: "1",
        profileId: "backend-dev",
        success: true,
        labels: ["api", "backend"]
      });

      const result = route({
        id: "2",
        title: "Fix API endpoint",
        labels: ["api"]
      });

      const backendScore = result.find(r => r.profileId === "backend-dev");
      expect(backendScore).toBeDefined();
      expect(backendScore.score).toBeGreaterThan(0);
    });

    it("scores profiles by keyword matching", () => {
      recordOutcome({
        ticketId: "1",
        profileId: "frontend-dev",
        success: true,
        keywords: ["react", "component", "ui"]
      });

      const result = route({
        id: "2",
        title: "Build React component for user profile"
      });

      const frontendScore = result.find(r => r.profileId === "frontend-dev");
      expect(frontendScore?.score).toBeGreaterThan(0);
    });

    it("penalizes profiles with low success rate", () => {
      // Record failures
      for (let i = 0; i < 5; i++) {
        recordOutcome({
          ticketId: `fail-${i}`,
          profileId: "unreliable",
          success: false,
          labels: ["test"]
        });
      }

      // Record success
      recordOutcome({
        ticketId: "success",
        profileId: "reliable",
        success: true,
        labels: ["test"]
      });

      const result = route({ id: "new", title: "test", labels: ["test"] });
      const reliable = result.find(r => r.profileId === "reliable");
      const unreliable = result.find(r => r.profileId === "unreliable");

      expect(reliable.score).toBeGreaterThan(unreliable?.score || 0);
    });
  });

  describe("getStats", () => {
    it("computes profile statistics", () => {
      recordOutcome({ ticketId: "1", profileId: "dev", success: true, duration: 1000 });
      recordOutcome({ ticketId: "2", profileId: "dev", success: false, duration: 500 });

      const stats = getStats();
      expect(stats.totalOutcomes).toBe(2);
      expect(stats.profileStats.dev.attempts).toBe(2);
      expect(stats.profileStats.dev.successes).toBe(1);
      expect(stats.profileStats.dev.avgDuration).toBe(750);
    });
  });
});
