**Missing Coverage:**
- Stale agent detection
- Memory threshold warnings
- Event emission on health issues

**Test Skeleton:**

```typescript
// test/integration/health-monitor.test.ts
import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { init, check, getStatus, stop, STALE_AGENT_THRESHOLD_MS, MEMORY_THRESHOLD_MB } from "@zana/core/src/health-monitor.ts";

describe("health-monitor", () => {
  afterEach(() => {
    stop();
  });

  describe("checkStaleAgents", () => {
    it("emits event for stale agents", () => {
      const mockBus = { emit: vi.fn() };
      const pastTime = new Date(Date.now() - STALE_AGENT_THRESHOLD_MS - 1000);

      const getAgents = () => [{
        id: "agent-1",
        state: "running",
        lastActivityAt: pastTime.toISOString(),
        profileName: "test"
      }];

      init(getAgents);
      check();

      expect(mockBus.emit).toHaveBeenCalledWith("health:stale-agent", expect.objectContaining({
        agentId: "agent-1"
      }));
    });

    it("ignores terminated agents", () => {
      const getAgents = () => [{
        id: "agent-1",
        state: "terminated",
        lastActivityAt: new Date(0).toISOString()
      }];

      init(getAgents);
      check(); // Should not emit event
    });
  });

  describe("getStatus", () => {
    it("returns health status", () => {
      const status = getStatus(() => [
        { id: "1", state: "running" },
        { id: "2", state: "terminated" }
      ]);

      expect(status.status).toBe("ok");
      expect(status.agents.total).toBe(2);
      expect(status.agents.active).toBe(1);
      expect(status.memory.heapUsed).toBeGreaterThan(0);
      expect(status.uptime).toBeGreaterThan(0);
    });
  });
});
