// test/integration/vector-memory.test.ts
import { describe, it, expect, beforeEach } from "vitest";
import { init, store, search, promote, maintain, stats } from "@zana/core/src/vector-memory.ts";

describe("vector-memory", () => {
  beforeEach(() => {
    init();
  });

  describe("store and search", () => {
    it("stores and retrieves by semantic similarity", () => {
      store({ content: "implement user authentication system", tier: "episodic" });
      store({ content: "build payment gateway integration", tier: "episodic" });

      const results = search("authentication login system");
      expect(results.length).toBeGreaterThan(0);
      expect(results[0].content).toContain("authentication");
    });

    it("filters by tier", () => {
      store({ content: "test content", tier: "semantic" });
      store({ content: "test content 2", tier: "working" });

      const semantic = search("test", { tier: "semantic" });
      expect(semantic.length).toBe(1);
      expect(semantic[0].tier).toBe("semantic");
    });

    it("filters by tags", () => {
      store({
        content: "feature implementation",
        metadata: { tags: ["backend", "api"] },
        tier: "episodic"
      });

      const results = search("implementation", { tags: ["backend"] });
      expect(results.length).toBeGreaterThan(0);
    });

    it("respects minScore threshold", () => {
      store({ content: "machine learning model training", tier: "episodic" });

      const highThreshold = search("database query", { minScore: 0.8 });
      expect(highThreshold.length).toBe(0); // No match
    });
  });

  describe("maintain", () => {
    it("expires working memory after TTL", () => {
      // Mock time passage
      const { id } = store({ content: "temp data", tier: "working" });

      // Fast-forward time (would need time mocking)
      const result = maintain();
      expect(result.expired).toBeGreaterThanOrEqual(0);
    });

    it("promotes episodic to semantic on high overlap", () => {
      store({ content: "architecture pattern singleton", tier: "episodic" });
      store({ content: "singleton architecture design", tier: "episodic" });
      store({ content: "design singleton pattern", tier: "episodic" });

      const result = maintain();
      expect(result.consolidated).toBeGreaterThan(0);
    });
  });

  describe("stats", () => {
    it("reports memory statistics", () => {
      store({ content: "test", tier: "working" });
      store({ content: "test", tier: "episodic" });
      store({ content: "test", tier: "semantic" });

      const s = stats();
      expect(s.total).toBe(3);
      expect(s.byTier.working).toBe(1);
      expect(s.byTier.episodic).toBe(1);
      expect(s.byTier.semantic).toBe(1);
    });
  });
});
