**Missing Coverage:**
- Token generation and validation
- Timing-safe comparison
- CORS origin validation
- Bearer token parsing

**Test Skeleton:**

```typescript
// test/integration/auth-middleware.test.ts
import { describe, it, expect } from "vitest";
import { init, authenticate, getToken, isAllowedOrigin, ALLOWED_ORIGINS } from "@zana/core/src/auth-middleware.ts";

describe("auth-middleware", () => {
  describe("authenticate", () => {
    it("accepts valid bearer token", () => {
      init({ token: "test-secret-token" });
      const req = {
        headers: {
          authorization: "Bearer test-secret-token"
        }
      };
      expect(authenticate(req)).toBe(true);
    });

    it("rejects invalid token", () => {
      init({ token: "correct-token" });
      const req = {
        headers: { authorization: "Bearer wrong-token" }
      };
      expect(authenticate(req)).toBe(false);
    });

    it("rejects malformed authorization header", () => {
      init({ token: "test" });
      expect(authenticate({ headers: { authorization: "test" } })).toBe(false);
      expect(authenticate({ headers: { authorization: "Basic dGVzdA==" } })).toBe(false);
    });

    it("rejects missing authorization header", () => {
      init({ token: "test" });
      expect(authenticate({ headers: {} })).toBe(false);
    });

    it("rejects unauthorized origins", () => {
      init({ token: "test" });
      const req = {
        headers: {
          origin: "https://evil.com",
          authorization: "Bearer test"
        }
      };
      expect(authenticate(req)).toBe(false);
    });

    it("allows whitelisted origins", () => {
      init({ token: "test" });
      const req = {
        headers: {
          origin: "http://localhost:3000",
          authorization: "Bearer test"
        }
      };
      expect(authenticate(req)).toBe(true);
    });

    it("uses timing-safe comparison to prevent timing attacks", () => {
      init({ token: "a".repeat(64) });

      // Both should take similar time (within margin)
      const start1 = performance.now();
      authenticate({ headers: { authorization: "Bearer " + "b".repeat(64) } });
      const time1 = performance.now() - start1;

      const start2 = performance.now();
      authenticate({ headers: { authorization: "Bearer " + "a".repeat(63) + "b" } });
      const time2 = performance.now() - start2;

      // Timing difference should be minimal (< 1ms for timing-safe comparison)
      expect(Math.abs(time1 - time2)).toBeLessThan(1);
    });
  });
});
