// test/integration/guardrails.test.ts
import { describe, it, expect } from "vitest";
import { noSecrets, jsonParse, jsonSchema, maxLength, fileExists, containsPattern } from "@zana/core/src/guardrails/builtins.ts";

describe("guardrails", () => {
  describe("noSecrets", () => {
    it("detects OpenAI API keys", () => {
      const guard = noSecrets();
      const result = guard.validate("Here's the key: sk-1234567890abcdefghijk");
      expect(result.pass).toBe(false);
      expect(result.feedback).toContain("secrets");
    });

    it("detects GitHub personal access tokens", () => {
      const guard = noSecrets();
      expect(guard.validate("Token: ghp_" + "a".repeat(36)).pass).toBe(false);
      expect(guard.validate("Token: gho_" + "a".repeat(36)).pass).toBe(false);
    });

    it("detects private keys", () => {
      const guard = noSecrets();
      const result = guard.validate("-----BEGIN RSA PRIVATE KEY-----\nMIIE...");
      expect(result.pass).toBe(false);
    });

    it("detects AWS access keys", () => {
      const guard = noSecrets();
      const result = guard.validate("Access: AKIAIOSFODNN7EXAMPLE");
      expect(result.pass).toBe(false);
    });

    it("detects Slack tokens", () => {
      const guard = noSecrets();
      expect(guard.validate("xoxb-123-456-789").pass).toBe(false);
      expect(guard.validate("xoxp-123-456-789").pass).toBe(false);
    });

    it("allows safe content", () => {
      const guard = noSecrets();
      expect(guard.validate("This is safe text").pass).toBe(true);
    });
  });

  describe("jsonParse", () => {
    it("accepts valid JSON", () => {
      const guard = jsonParse();
      const result = guard.validate('{"key": "value"}');
      expect(result.pass).toBe(true);
      expect(result.parsedOutput).toEqual({ key: "value" });
    });

    it("extracts JSON from markdown code blocks", () => {
      const guard = jsonParse();
      const result = guard.validate('```json\n{"test": true}\n```');
      expect(result.pass).toBe(true);
      expect(result.parsedOutput).toEqual({ test: true });
    });

    it("rejects invalid JSON", () => {
      const guard = jsonParse();
      const result = guard.validate("{invalid json}");
      expect(result.pass).toBe(false);
      expect(result.feedback).toContain("not valid JSON");
    });
  });

  describe("maxLength", () => {
    it("accepts content within limit", () => {
      const guard = maxLength(100);
      expect(guard.validate("short text").pass).toBe(true);
    });

    it("rejects content exceeding limit", () => {
      const guard = maxLength(10);
      const result = guard.validate("this is too long");
      expect(result.pass).toBe(false);
      expect(result.feedback).toContain("Maximum allowed is 10");
    });
  });
});
