      init({ token: "test" });
      expect(authenticate({ headers: {} })).toBe(false);
    });

    it("rejects unauthorized origins", () => {
      init({ token: "test" });
      const req = {
        headers: {
          origin: "https://evil.com",
          authorization: "Bearer test"
        }
      };
      expect(authenticate(req)).toBe(false);
    });

    it("allows whitelisted origins", () => {
      init({ token: "test" });
